341: // UnmarshalYAML implements the yaml.Unmarshaler interface.
342: func (c *TLSConfig) UnmarshalYAML(unmarshal func(interface{}) error) error {
343: 	type plain TLSConfig
344: 	return unmarshal((*plain)(c))
345: }
