309: // GetScrapeConfigs returns the read-only, validated scrape configurations including
310: // the ones from the scrape_config_files.
311: // This method does not write to config, and it's concurrency safe (the pointer receiver is for efficiency).
312: // This method also assumes the Config was created by Load or LoadFile function, it returns error
313: // if it was not. We can't re-validate or apply globals here due to races,
314: // read more https://github.com/prometheus/prometheus/issues/15538.
315: func (c *Config) GetScrapeConfigs() ([]*ScrapeConfig, error) {
316: 	if !c.loaded {
317: 		// Programmatic error, we warn before more confusing errors would happen due to lack of the globalization.
318: 		return nil, errors.New("scrape config cannot be fetched, main config was not validated and loaded correctly; should not happen")
319: 	}
320: 
321: 	scfgs := make([]*ScrapeConfig, len(c.ScrapeConfigs))
322: 	jobNames := map[string]string{}
323: 	for i, scfg := range c.ScrapeConfigs {
324: 		jobNames[scfg.JobName] = "main config file"
325: 		scfgs[i] = scfg
326: 	}
327: 
328: 	// Re-read and validate the dynamic scrape config rules.
329: 	for _, pat := range c.ScrapeConfigFiles {
330: 		fs, err := filepath.Glob(pat)
331: 		if err != nil {
332: 			// The only error can be a bad pattern.
333: 			return nil, fmt.Errorf("error retrieving scrape config files for %q: %w", pat, err)
334: 		}
335: 		for _, filename := range fs {
336: 			cfg := ScrapeConfigs{}
337: 			content, err := os.ReadFile(filename)
338: 			if err != nil {
339: 				return nil, fileErr(filename, err)
340: 			}
341: 			err = yaml.UnmarshalStrict(content, &cfg)
342: 			if err != nil {
343: 				return nil, fileErr(filename, err)
344: 			}
345: 			for _, scfg := range cfg.ScrapeConfigs {
346: 				if err := scfg.Validate(c.GlobalConfig); err != nil {
347: 					return nil, fileErr(filename, err)
348: 				}
349: 
350: 				if f, ok := jobNames[scfg.JobName]; ok {
351: 					return nil, fileErr(filename, fmt.Errorf("found multiple scrape configs with job name %q, first found in %s", scfg.JobName, f))
352: 				}
353: 				jobNames[scfg.JobName] = fmt.Sprintf("%q", filePath(filename))
354: 
355: 				scfg.SetDirectory(filepath.Dir(filename))
356: 				scfgs = append(scfgs, scfg)
357: 			}
358: 		}
359: 	}
360: 	return scfgs, nil
361: }
